node -e "const fs=require('fs');const s=JSON.parse(fs.readFileSync('bot-state.json','utf8'));let c=false;for(let w of s.watchItems){if(w.symbol.toLowerCase()==='cope'){w.orders=w.orders.filter(o=>!['error','paused','pending'].includes(o.status));const t=245409.20079,a=4.5,p=a/t;for(let o of w.orders)if(o.type==='dca'||o.type==='entry'){o.price=p;o.filledPrice=p;}if(w.filledBuys&&w.filledBuys.length){w.filledBuys[0].price=p;w.filledBuys[0].tokens=t;}if(w.orders.length&&w.orders[0].type==='dca'){w.orders[0].type='entry';w.orders[0].note='Fijado';}c=true;}}if(c){fs.writeFileSync('bot-state.json',JSON.stringify(s,null,2));console.log('Arreglado! Reinicia pm2');}"
